from collections import Counter
def token_f1(a, b):
    # a tokens candidate, b tokens substring
    ca = Counter(a.split())
    cb = Counter(b.split())
    # multiset intersection count
    inter = 0
    for tok in ca:
        inter += min(ca[tok], cb.get(tok,0))
    if inter==0:
        return 0.0, 0, len(a.split()), len(b.split())
    p = inter / sum(ca.values())
    r = inter / sum(cb.values())
    if p + r == 0:
        return 0.0, inter, sum(ca.values()), sum(cb.values())
    f1 = 2*p*r/(p+r)
    return f1, inter, sum(ca.values()), sum(cb.values())

